(function(){"use strict";const metaEl=document.getElementById("crm-dwr-meta");let meta={staff_portal:false,staff_id:null,staff_name:""};try{meta=JSON.parse(metaEl?.textContent||"{}");}catch{}
const staffPortal=!!meta.staff_portal;const myStaffId=meta.staff_id?Number(meta.staff_id):null;const form=document.getElementById("crm-dwr-form");const editIdEl=document.getElementById("crm-dwr-edit-id");const dateEl=document.getElementById("crm-dwr-date");const staffEl=document.getElementById("crm-dwr-staff");const hoursEl=document.getElementById("crm-dwr-hours");const summaryEl=document.getElementById("crm-dwr-summary");const tomorrowEl=document.getElementById("crm-dwr-tomorrow");const supportEl=document.getElementById("crm-dwr-support");const tasksBody=document.getElementById("crm-dwr-tasks-body");const okEl=document.getElementById("crm-dwr-ok");const errEl=document.getElementById("crm-dwr-err");const historyBody=document.getElementById("crm-dwr-history-body");const historyEmpty=document.getElementById("crm-dwr-history-empty");const filterFrom=document.getElementById("crm-dwr-filter-from");const filterTo=document.getElementById("crm-dwr-filter-to");const filterStaff=document.getElementById("crm-dwr-filter-staff");const detailModal=document.getElementById("crm-dwr-detail-modal");const detailBody=document.getElementById("crm-dwr-detail-body");const detailTitle=document.getElementById("crm-dwr-detail-title");let staffList=[];let detailReport=null;function esc(s){return String(s??"").replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;").replace(/"/g,"&quot;");}
function todayIso(){const d=new Date();const m=String(d.getMonth()+1).padStart(2,"0");const day=String(d.getDate()).padStart(2,"0");return`${d.getFullYear()}-${m}-${day}`;}
function monthStartIso(){const d=new Date();const m=String(d.getMonth()+1).padStart(2,"0");return`${d.getFullYear()}-${m}-01`;}
function showMsg(el,text){if(!el)return;if(text){el.textContent=text;el.hidden=false;}else{el.hidden=true;}}
async function reqJson(url,opts){const res=await fetch(url,{credentials:"same-origin",headers:{"Content-Type":"application/json",Accept:"application/json"},...opts,});const data=await res.json().catch(()=>({}));if(!res.ok)throw new Error(data.error||"Yêu cầu thất bại.");return data;}
function taskRowHtml(task,idx){const t=task||{};return`<tr data-task-idx="${idx}">
      <td><input type="text" data-f="time_slot" value="${esc(t.time_slot || "")}" placeholder="08:30-10:00" /></td>
      <td><input type="text" data-f="title" value="${esc(t.title || "")}" placeholder="Công việc" required /></td>
      <td><input type="text" data-f="detail" value="${esc(t.detail || "")}" placeholder="Mô tả" /></td>
      <td><input type="text" data-f="related" value="${esc(t.related || "")}" placeholder="Case / KH" /></td>
      <td><input type="number" data-f="progress_pct" min="0" max="100" value="${t.progress_pct != null ? esc(t.progress_pct) : ""}" placeholder="%" /></td>
      <td><input type="text" data-f="result" value="${esc(t.result || "")}" placeholder="Kết quả" /></td>
      <td><button type="button" class="btn-secondary crm-dwr-rm-task" title="Xóa dòng">×</button></td>
    </tr>`;}
function renderTasks(tasks){if(!tasksBody)return;const list=Array.isArray(tasks)&&tasks.length?tasks:[{}];tasksBody.innerHTML=list.map((t,i)=>taskRowHtml(t,i)).join("");}
function collectTasks(){if(!tasksBody)return[];return[...tasksBody.querySelectorAll("tr")].map((tr)=>{const get=(f)=>{const el=tr.querySelector(`[data-f="${f}"]`);return el&&"value"in el?String(el.value||"").trim():"";};const pctRaw=get("progress_pct");return{time_slot:get("time_slot"),title:get("title"),detail:get("detail"),related:get("related"),progress_pct:pctRaw===""?null:Number(pctRaw),result:get("result"),};}).filter((t)=>t.title);}
function fillStaffSelects(){const opts='<option value="">— Chọn nhân viên —</option>'+
staffList.map((s)=>{const code=(s.internal_code||"").toString().trim();const label=code?`${s.name} (${code})`:s.name;return`<option value="${esc(String(s.id))}">${esc(label)}</option>`;}).join("");if(staffEl)staffEl.innerHTML=opts;if(filterStaff){filterStaff.innerHTML='<option value="">Tất cả</option>'+
staffList.map((s)=>`<option value="${esc(String(s.id))}">${esc(s.name || "")}</option>`).join("");}}
async function loadStaff(){if(staffPortal)return;const data=await reqJson("/api/crm/staff?include_inactive=0");staffList=(data.staff||[]).filter((s)=>s.active!==0);fillStaffSelects();}
function resetForm(){if(editIdEl)editIdEl.value="";if(dateEl)dateEl.value=todayIso();if(hoursEl)hoursEl.value="";if(summaryEl)summaryEl.value="";if(tomorrowEl)tomorrowEl.value="";if(supportEl)supportEl.value="";renderTasks([{}]);showMsg(okEl,"");showMsg(errEl,"");if(staffEl&&myStaffId)staffEl.value=String(myStaffId);}
function fillForm(report){if(!report)return;if(editIdEl)editIdEl.value=String(report.id||"");if(dateEl)dateEl.value=report.report_date||todayIso();if(staffEl&&report.staff_id)staffEl.value=String(report.staff_id);if(hoursEl)hoursEl.value=report.hours_worked!=null?String(report.hours_worked):"";if(summaryEl)summaryEl.value=report.summary||"";if(tomorrowEl)tomorrowEl.value=report.tomorrow_plan||"";if(supportEl)supportEl.value=report.support_needed||"";renderTasks(report.tasks&&report.tasks.length?report.tasks:[{}]);}
async function loadHistory(){const p=new URLSearchParams();if(filterFrom?.value)p.set("from",filterFrom.value);if(filterTo?.value)p.set("to",filterTo.value);if(!staffPortal&&filterStaff?.value)p.set("staff_id",filterStaff.value);p.set("limit","80");const data=await reqJson(`/api/crm/daily-work-reports?${p.toString()}`);const rows=data.reports||[];if(!historyBody)return;if(!rows.length){historyBody.innerHTML="";if(historyEmpty)historyEmpty.hidden=false;return;}
if(historyEmpty)historyEmpty.hidden=true;const colSpan=staffPortal?5:6;historyBody.innerHTML=rows.map((r)=>{const sum=esc((r.summary||"").slice(0,80)+((r.summary||"").length>80?"…":""));const staffCell=staffPortal?"":`<td>${esc(r.staff_name || "")}${r.staff_code ? `<span class="muted">(${esc(r.staff_code)})</span>` : ""}</td>`;return`<tr>
          <td>${esc(r.report_date || "")}</td>
          ${staffCell}
          <td>${sum || "—"}</td>
          <td>${r.hours_worked != null ? esc(r.hours_worked) : "—"}</td>
          <td class="muted">${esc((r.updated_at || "").slice(0, 16))}</td>
          <td><button type="button" class="btn-secondary crm-dwr-view" data-id="${esc(String(r.id))}">Xem</button></td>
        </tr>`;}).join("");}
function renderDetail(report){detailReport=report;if(detailTitle){detailTitle.textContent=`Báo cáo ${report.report_date || ""} — ${report.staff_name || ""}`;}
if(!detailBody)return;const tasks=Array.isArray(report.tasks)?report.tasks:[];const tasksHtml=tasks.length?`<table class="crm-dwr-detail-tasks"><thead><tr>
          <th>Giờ</th><th>Công việc</th><th>Chi tiết</th><th>Liên quan</th><th>%</th><th>Kết quả</th>
        </tr></thead><tbody>${tasks
          .map(
            (t) => `<tr><td>${esc(t.time_slot||"")}</td><td>${esc(t.title||"")}</td><td>${esc(t.detail||"")}</td><td>${esc(t.related||"")}</td><td>${t.progress_pct!=null?esc(t.progress_pct):""}</td><td>${esc(t.result||"")}</td></tr>`,
          )
          .join("")}</tbody></table>`:'<p class="muted">Không có dòng công việc chi tiết.</p>';detailBody.innerHTML=`
      <div class="crm-dwr-detail-meta">
        <span><strong>Mã NV:</strong> ${esc(report.staff_code || "—")}</span>
        <span><strong>Phòng ban:</strong> ${esc(report.department || "—")}</span>
        <span><strong>Giờ làm:</strong> ${report.hours_worked != null ? esc(report.hours_worked) : "—"}</span>
      </div>
      <div class="crm-dwr-detail-block"><h4>Tổng kết</h4><p>${esc(report.summary || "—").replace(/\n/g, "<br>")}</p></div>
      <div class="crm-dwr-detail-block"><h4>Kế hoạch ngày mai</h4><p>${esc(report.tomorrow_plan || "—").replace(/\n/g, "<br>")}</p></div>
      <div class="crm-dwr-detail-block"><h4>Hỗ trợ cần</h4><p>${esc(report.support_needed || "—").replace(/\n/g, "<br>")}</p></div>
      <div class="crm-dwr-detail-block"><h4>Công việc</h4>${tasksHtml}</div>`;if(detailModal)detailModal.hidden=false;}
async function openDetail(id){const data=await reqJson(`/api/crm/daily-work-reports/${id}`);renderDetail(data.report||data);}
document.getElementById("crm-dwr-add-task")?.addEventListener("click",()=>{if(!tasksBody)return;const idx=tasksBody.querySelectorAll("tr").length;tasksBody.insertAdjacentHTML("beforeend",taskRowHtml({},idx));});tasksBody?.addEventListener("click",(ev)=>{const btn=ev.target.closest(".crm-dwr-rm-task");if(!btn)return;const tr=btn.closest("tr");if(tr&&tasksBody.querySelectorAll("tr").length>1)tr.remove();});form?.addEventListener("submit",async(ev)=>{ev.preventDefault();showMsg(okEl,"");showMsg(errEl,"");const reportDate=(dateEl?.value||"").trim();if(!reportDate){showMsg(errEl,"Chọn ngày báo cáo.");return;}
const tasks=collectTasks();if(!tasks.length&&!(summaryEl?.value||"").trim()){showMsg(errEl,"Thêm ít nhất một công việc hoặc tổng kết.");return;}
const payload={report_date:reportDate,summary:(summaryEl?.value||"").trim(),tomorrow_plan:(tomorrowEl?.value||"").trim(),support_needed:(supportEl?.value||"").trim(),hours_worked:(hoursEl?.value||"").trim(),tasks,status:"submitted",};if(!staffPortal&&staffEl?.value)payload.staff_id=Number(staffEl.value);const editId=(editIdEl?.value||"").trim();try{if(editId){await reqJson(`/api/crm/daily-work-reports/${editId}`,{method:"PATCH",body:JSON.stringify(payload),});showMsg(okEl,"Đã cập nhật báo cáo.");}else{await reqJson("/api/crm/daily-work-reports",{method:"POST",body:JSON.stringify(payload),});showMsg(okEl,"Đã lưu báo cáo.");}
await loadHistory();}catch(e){showMsg(errEl,e instanceof Error?e.message:"Không lưu được.");}});document.getElementById("crm-dwr-reset")?.addEventListener("click",()=>resetForm());document.getElementById("crm-dwr-filter-btn")?.addEventListener("click",()=>{loadHistory().catch((e)=>showMsg(errEl,e.message));});historyBody?.addEventListener("click",(ev)=>{const btn=ev.target.closest(".crm-dwr-view");if(!btn)return;const id=btn.getAttribute("data-id");if(id)openDetail(id).catch((e)=>showMsg(errEl,e.message));});document.getElementById("crm-dwr-detail-edit")?.addEventListener("click",()=>{if(detailReport){fillForm(detailReport);if(detailModal)detailModal.hidden=true;form?.scrollIntoView({behavior:"smooth",block:"start"});}});document.querySelectorAll("[data-close-dwr-modal]").forEach((el)=>{el.addEventListener("click",()=>{if(detailModal)detailModal.hidden=true;});});dateEl?.addEventListener("change",async()=>{const d=(dateEl.value||"").trim();if(!d)return;try{const p=new URLSearchParams({report_date:d});if(!staffPortal&&staffEl?.value)p.set("staff_id",staffEl.value);const data=await reqJson(`/api/crm/daily-work-reports/by-date?${p.toString()}`);if(data.report)fillForm(data.report);}catch{}});async function init(){if(dateEl)dateEl.value=todayIso();if(filterFrom)filterFrom.value=monthStartIso();if(filterTo)filterTo.value=todayIso();renderTasks([{}]);try{await loadStaff();await loadHistory();}catch(e){showMsg(errEl,e instanceof Error?e.message:"Không tải được dữ liệu.");}}
init();})();